// Cloudflare Worker with SendGrid and Stripe Integration

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Content-Type': 'application/json',
};

class APIError extends Error {
  constructor(message, status = 500, details = null) {
    super(message);
    this.status = status;
    this.details = details;
  }
}

async function sendEmail(to, subject, content, apiKey) {
  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email: to }],
          subject: subject,
        },
      ],
      from: { email: 'noreply@yourdomain.com' },
      content: [
        {
          type: 'text/html',
          value: content,
        },
      ],
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new APIError(
      'Failed to send email',
      response.status,
      errorText
    );
  }

  return { success: true, message: 'Email sent successfully' };
}

async function createPaymentIntent(amount, currency, apiKey) {
  const params = new URLSearchParams({
    amount: Math.round(amount * 100),
    currency: currency || 'usd',
    'automatic_payment_methods[enabled]': 'true',
  });

  const response = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  });

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      'Failed to create payment intent',
      response.status,
      data.error
    );
  }

  return {
    success: true,
    clientSecret: data.client_secret,
    paymentIntentId: data.id,
  };
}

async function retrievePayment(paymentIntentId, apiKey) {
  const response = await fetch(
    `https://api.stripe.com/v1/payment_intents/${paymentIntentId}`,
    {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
      },
    }
  );

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      'Failed to retrieve payment',
      response.status,
      data.error
    );
  }

  return {
    success: true,
    status: data.status,
    amount: data.amount / 100,
    currency: data.currency,
  };
}

async function createCustomer(email, name, apiKey) {
  const params = new URLSearchParams({
    email: email,
    name: name || '',
  });

  const response = await fetch('https://api.stripe.com/v1/customers', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  });

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      'Failed to create customer',
      response.status,
      data.error
    );
  }

  return {
    success: true,
    customerId: data.id,
    email: data.email,
  };
}

async function sendTransactionEmail(to, amount, currency, transactionId, sendgridKey) {
  const content = `
    <h2>Payment Confirmation</h2>
    <p>Thank you for your payment!</p>
    <p><strong>Amount:</strong> ${amount} ${currency.toUpperCase()}</p>
    <p><strong>Transaction ID:</strong> ${transactionId}</p>
    <p>If you have any questions, please contact our support team.</p>
  `;

  return await sendEmail(
    to,
    'Payment Confirmation',
    content,
    sendgridKey
  );
}

function validateAPIKey(request, expectedKey) {
  const authHeader = request.headers.get('Authorization');
  
  if (!authHeader) {
    throw new APIError('Missing authorization header', 401);
  }

  const token = authHeader.replace('Bearer ', '');
  
  if (token !== expectedKey) {
    throw new APIError('Invalid API key', 403);
  }

  return true;
}

async function handleEmailRequest(request, env) {
  const { to, subject, content } = await request.json();

  if (!to || !subject || !content) {
    throw new APIError('Missing required fields: to, subject, content', 400);
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(to)) {
    throw new APIError('Invalid email address', 400);
  }

  return await sendEmail(to, subject, content, env.SENDGRID_API_KEY);
}

async function handlePaymentRequest(request, env) {
  const { amount, currency } = await request.json();

  if (!amount || amount <= 0) {
    throw new APIError('Invalid amount', 400);
  }

  return await createPaymentIntent(amount, currency, env.STRIPE_SECRET_KEY);
}

async function handlePaymentStatusRequest(request, env) {
  const url = new URL(request.url);
  const paymentIntentId = url.searchParams.get('id');

  if (!paymentIntentId) {
    throw new APIError('Missing payment intent ID', 400);
  }

  return await retrievePayment(paymentIntentId, env.STRIPE_SECRET_KEY);
}

async function handleCustomerRequest(request, env) {
  const { email, name } = await request.json();

  if (!email) {
    throw new APIError('Missing required field: email', 400);
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) {
    throw new APIError('Invalid email address', 400);
  }

  return await createCustomer(email, name, env.STRIPE_SECRET_KEY);
}

async function handleCheckoutRequest(request, env) {
  const { email, amount, currency, customerName } = await request.json();

  if (!email || !amount || amount <= 0) {
    throw new APIError('Missing or invalid required fields', 400);
  }

  const customer = await createCustomer(email, customerName, env.STRIPE_SECRET_KEY);
  const payment = await createPaymentIntent(amount, currency, env.STRIPE_SECRET_KEY);

  await sendTransactionEmail(
    email,
    amount,
    currency || 'usd',
    payment.paymentIntentId,
    env.SENDGRID_API_KEY
  );

  return {
    success: true,
    customerId: customer.customerId,
    clientSecret: payment.clientSecret,
    paymentIntentId: payment.paymentIntentId,
    message: 'Checkout initiated and confirmation email sent',
  };
}

async function handleRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  validateAPIKey(request, env.API_KEY);

  switch (path) {
    case '/email/send':
      if (request.method !== 'POST') {
        throw new APIError('Method not allowed', 405);
      }
      return await handleEmailRequest(request, env);

    case '/payment/create':
      if (request.method !== 'POST') {
        throw new APIError('Method not allowed', 405);
      }
      return await handlePaymentRequest(request, env);

    case '/payment/status':
      if (request.method !== 'GET') {
        throw new APIError('Method not allowed', 405);
      }
      return await handlePaymentStatusRequest(request, env);

    case '/customer/create':
      if (request.method !== 'POST') {
        throw new APIError('Method not allowed', 405);
      }
      return await handleCustomerRequest(request, env);

    case '/checkout':
      if (request.method !== 'POST') {
        throw new APIError('Method not allowed', 405);
      }
      return await handleCheckoutRequest(request, env);

    case '/health':
      return { status: 'healthy', timestamp: new Date().toISOString() };

    default:
      throw new APIError('Endpoint not found', 404);
  }
}

export default {
  async fetch(request, env, ctx) {
    if (request.method === 'OPTIONS') {
      return new Response(null, {
        headers: CORS_HEADERS,
      });
    }

    try {
      if (!env.SENDGRID_API_KEY || !env.STRIPE_SECRET_KEY || !env.API_KEY) {
        throw new APIError('Missing required environment variables', 500);
      }

      const result = await handleRequest(request, env);

      return new Response(JSON.stringify(result), {
        status: 200,
        headers: CORS_HEADERS,
      });
    } catch (error) {
      console.error('Error:', error);

      const status = error instanceof APIError ? error.status : 500;
      const message = error instanceof APIError ? error.message : 'Internal server error';
      const details = error instanceof APIError ? error.details : null;

      return new Response(
        JSON.stringify({
          success: false,
          error: message,
          details: details,
        }),
        {
          status: status,
          headers: CORS_HEADERS,
        }
      );
    }
  },
};